mapper.select:
select a.org_id, a.org_name, a.parent_org_id, a.path_code from po_organization a
and a.parent_org_id =#{parentOrgId}
and a.org_name like concat(concat('%',#{keyword}),'%')
#{orgId}
order by a.org_index asc

select
    count(1)
from po_organization


        and org_name =#{orgName}


        and org_code =#{orgCode}


        and org_id !=#{orgIdNoEqual}

select a.user_id, a.user_code, a.user_name, #{orgId} as org_id from po_users a
a.user_id in ( select b.user_id from po_users_organization b where b.org_id = #{orgId}
#{item}
)

SELECT a.org_id, a.org_name, a.parent_org_id, a.path_code, count(b.org_id) AS total FROM po_organization a LEFT JOIN po_organization b ON strpos(concat('.', b.path_code, '.'), concat('.', a.org_id, '.')) > 0
and a.parent_org_id =#{parentOrgId}
and a.org_name like concat(concat('%',#{keyword}),'%')
#{orgId}
GROUP BY a.org_id, a.org_name, a.parent_org_id, a.path_code ORDER BY a.org_index asc

SELECT o.org_id as "orgId", o.org_name as "orgName", o.path_code as "pathCode", ( SELECT string_agg(parent.org_name, '-') FROM ( SELECT parent.org_name, parent.org_level FROM po_organization parent WHERE parent.org_id = ANY( SELECT unnest(string_to_array(o.path_code, '.')::bigint[]) ) ORDER BY parent.org_level ) parent ) as "pathName" FROM po_organization o WHERE o.org_id IN
#{orgId}
ORDER BY o.org_id
